import{ControlFlow}from"../utils/util";class TopNav{#callback=()=>{};#elmP=null;constructor(elmP,callback){this.#elmP=elmP,this.#callback=callback,this.selSize=this.#elmP.querySelector("#sel-size"),this.customWidthEl=this.#elmP.querySelector("#cw"),this.customHeightEl=this.#elmP.querySelector("#ch"),this.zoomInBtn=this.#elmP.querySelector("#btn-zin"),this.zoomOutBtn=this.#elmP.querySelector("#btn-zout"),this.zoomFitBtn=this.#elmP.querySelector("#btn-fit"),this.#init()}#init(){this.#eventListener()}#eventListener(){this.#sizeEvents(),this.#zoomEvents()}#sizeEvents(){this.selSize.addEventListener("change",(()=>{const{value:size}=this.selSize;if("custom"===size)this.customWidthEl.style.display=this.customHeightEl.style.display="inline-block";else{this.customWidthEl.style.display=this.customHeightEl.style.display="none";const[w,h]=size.split(",").map(Number);this.customWidthEl.value=w,this.customHeightEl.value=h,this.#callback({action:"setSize",size:size})}})),[this.customWidthEl,this.customHeightEl].forEach(((elm,idx,arr)=>{const handler=ControlFlow.debounce((e=>{this.#callback({action:"setSize",custom:{w:Number(arr[0].value),h:Number(arr[1].value)}})}),1e3);elm.addEventListener("input",handler)}))}#zoomEvents(){this.zoomInBtn.addEventListener("click",(()=>{this.#callback({action:"setZoom",value:"in"})})),this.zoomOutBtn.addEventListener("click",(()=>{this.#callback({action:"setZoom",value:"out"})})),this.zoomFitBtn.addEventListener("click",(()=>this.#callback({action:"setZoom",value:"fit"})))}}export{TopNav};